-- SEED DATA UNTUK SOAL WAWANCARA\n-- Format: (kategori, pertanyaan, jawaban_paling_tepat, penjelasan_jawaban)\n\nINSERT INTO soal_wawancara (id, kategori, pertanyaan, jawaban_paling_tepat, penjelasan_jawaban) VALUES\n(1, 'KEPRIBADIAN (Love, Sex, Dating)', 'Bagaimana sikap remaja Kristen dalam menghadapi tekanan pergaulan bebas?', 'Remaja Kristen harus berpegang teguh pada iman, menjauhi pergaulan bebas, dan memiliki komitmen untuk hidup kudus sesuai Firman Tuhan dalam 1 Korintus 6:19-20', 'Tubuh kita adalah bait Roh Kudus. Remaja teladan harus berani berkata "tidak" terhadap hal-hal yang merusak, serta mencari lingkungan pertemanan yang positif dan mendukung iman'),\n(2, 'KEPRIBADIAN (Love, Sex, Dating)', 'Jelaskan batasan pacaran yang sehat menurut iman Kristen!', 'Batasan pacaran sehat: tidak berduaan di tempat tertutup, menjaga pikiran dan perbuatan, saling mengingatkan dalam doa, serta fokus pada pengembangan diri dan pelayanan', 'Pacaran bukan tujuan akhir tetapi masa persiapan menuju pernikahan. Hindari hal-hal yang membangkitkan nafsu sebelum waktunya. Orang tua dan pembina rohani perlu dilibatkan sebagai penasihat'),\n(3, 'KEPRIBADIAN (Love, Sex, Dating)', 'Bagaimana cara menjaga kekudusan diri di era digital saat ini?', 'Membatasi akses konten negatif, menggunakan media sosial untuk hal-hal positif, tidak mengirim atau menerima pesan bermuatan pornografi, serta memiliki akunabilitas dengan sahabat rohani', 'Era digital penuh godaan. Remaja teladan harus bijak menggunakan teknologi, memasang filter konten, dan berani memblokir akun-akun yang menjerumuskan'),\n(4, 'KEPRIBADIAN (Love, Sex, Dating)', 'Apa yang dimaksud dengan "cinta kasih" menurut Alkitab?', 'Cinta kasih adalah sabar, murah hati, tidak cemburu, tidak memegahkan diri, tidak sombong, tidak melakukan yang tidak sopan, tidak mencari keuntungan sendiri (1 Korintus 13:4-7)', 'Cinta sejati bukan hanya perasaan tetapi tindakan yang mengutamakan kebaikan orang lain. Cinta Kristen adalah agape - kasih tanpa syarat yang berasal dari Allah'),\n(5, 'KEPRIBADIAN (Love, Sex, Dating)', 'Bagaimana sikap Anda jika teman dekat mengajak berpacaran dengan sesama jenis?', 'Dengan tegas namun penuh kasih saya akan menolak, menjelaskan bahwa Alkitab mengajarkan pernikahan adalah antara laki-laki dan perempuan, dan tetap menjalin persahabatan tanpa mendukung praktik tersebut', 'Remaja teladan harus berani memegang kebenaran Alkitab tanpa kompromi, tetapi tetap mengasihi pribadi orangnya. Tolak dosanya, kasihi orangnya'),\n(6, 'KEPRIBADIAN (Love, Sex, Dating)', 'Bagaimana cara menghadapi rasa suka/suka kepada lawan jenis di usia remaja?', 'Alihkan perhatian pada kegiatan positif, fokus pada prestasi akademik dan pelayanan, ceritakan kepada orang tua/pembina, jangan dipendam sendiri, dan doakan orang tersebut', 'Perasaan suka adalah wajar tetapi perlu dikelola dengan bijak. Jangan terburu-buru menjalin hubungan pacaran di usia remaja karena belum siap secara mental dan finansial'),\n(7, 'KEPRIBADIAN (Love, Sex, Dating)', 'Apa dampak negatif dari seks bebas bagi remaja?', 'Dampak: kehamilan di luar nikah, aborsi, penyakit menular seksual (HIV/AIDS), trauma psikologis, putus sekolah, hilangnya masa depan, serta dosa yang merusak hubungan dengan Tuhan', 'Seks bebas merusak masa depan remaja. Alkitab tegas melarang percabulan (1 Korintus 6:18). Setiap dosa yang dilakukan di luar tubuh, tetapi orang yang melakukan percabulan berdosa terhadap tubuhnya sendiri'),\n(8, 'KEPRIBADIAN (Love, Sex, Dating)', 'Bagaimana remaja teladan bergaul dengan lawan jenis di gereja?', 'Bergaul secara terbuka dan sehat, tidak berduaan, menjaga jarak fisik yang pantas, berbicara dengan sopan, dan selalu dalam pengawasan orang dewasa/pembina', 'Remaja teladan harus menjaga nama baik dan kesaksian. Hindari situasi yang dapat menimbulkan fitnah atau godaan. Batasan yang jelas melindungi kedua belah pihak'),\n(9, 'KEPRIBADIAN (Love, Sex, Dating)', 'Apa yang harus dilakukan jika sudah terlanjur jatuh dalam dosa seksual?', 'Bertobat segera, mengaku dosa kepada Tuhan, meminta pertolongan dari pembina rohani/orang tua, menjauhi dosa tersebut, dan percaya akan pengampunan Allah', '1 Yohanes 1:9 - Jika kita mengaku dosa kita, Allah adalah setia dan adil, sehingga Ia akan mengampuni segala dosa kita. Pertobatan sejati ditandai dengan perubahan perilaku'),\n(10, 'KEPRIBADIAN (Love, Sex, Dating)', 'Bagaimana cara membangun karakter yang kuat sebagai remaja teladan?', 'Membangun hubungan intim dengan Tuhan melalui doa dan Alkitab, memiliki mentor rohani, disiplin dalam hal-hal kecil, belajar dari tokoh Alkitab seperti Daniel dan Timotius', 'Karakter tidak terbentuk dalam sehari tetapi melalui latihan dan ketekunan. Remaja teladan harus memiliki integritas: sama baiknya ketika dilihat maupun tidak dilihat orang'),\n(11, 'KEPRIBADIAN (Love, Sex, Dating)', 'Apa arti "menjadi teladan dalam perkataan" menurut 1 Timotius 4:12?', 'Berbicara dengan sopan, tidak berkata kotor, tidak bergosip, tidak berbohong, dan perkataan selalu membangun serta memberi pengharapan', 'Lidah memiliki kuasa atas kehidupan. Remaja teladan harus menjaga perkataannya karena dari perkataan akan dibenarkan atau dihukum (Matius 12:37)'),\n(12, 'KEPRIBADIAN (Love, Sex, Dating)', 'Bagaimana cara mengendalikan amarah/marah di usia remaja?', 'Berdoa terlebih dahulu, tarik napas dalam-dalam, jangan langsung merespon, cari tempat yang tenang, dan selesaikan masalah dengan kepala dingin', 'Amsal 16:32 - Orang yang sabar melebihi pahlawan. Kemarahan tidak menghasilkan kebenaran di hadapan Allah. Remaja teladan harus belajar menguasai diri'),\n(13, 'KEPRIBADIAN (Love, Sex, Dating)', 'Apa yang dimaksud dengan "Integritas" bagi seorang remaja?', 'Konsisten antara perkataan dan perbuatan, jujur dalam segala hal, bertanggung jawab, tidak munafik, dan melakukan kebenaran baik di depan maupun belakang', 'Integritas adalah pondasi kepemimpinan. Remaja teladan yang berintegritas dipercaya oleh banyak orang dan menjadi berkat bagi lingkungannya'),\n(14, 'KEPRIBADIAN (Love, Sex, Dating)', 'Bagaimana remaja teladan bersikap kepada orang tua?', 'Hormat, taat, membantu pekerjaan rumah, berbicara dengan lembut, tidak membantah, minta maaf jika salah, dan mendoakan mereka', 'Efesus 6:2-3 - Hormatilah ayahmu dan ibumu, ini adalah hukum yang pertama dengan janji, supaya kamu berbahagia dan panjang umurmu di bumi'),\n(15, 'KEPRIBADIAN (Love, Sex, Dating)', 'Bagaimana cara mengatasi rasa insecure/rendah diri di usia remaja?', 'Melihat diri sebagai ciptaan Allah yang berharga, fokus pada talenta yang diberikan Tuhan, tidak membandingkan diri dengan orang lain, dan mengembangkan potensi diri', 'Mazmur 139:14 - Aku bersyukur kepada-Mu karena kejadianku dahsyat dan ajaib. Setiap remaja unik dan memiliki panggilan khusus dari Tuhan'),\n(16, 'KEPRIBADIAN (Love, Sex, Dating)', 'Apa bahaya narkoba bagi remaja menurut pandangan Kristen?', 'Merusak tubuh yang adalah bait Roh Kudus (1 Korintus 6:19), menghancurkan masa depan, menjauhkan dari Tuhan, menyebabkan ketergantungan, dan berujung pada kematian jasmani rohani', 'Tubuh adalah milik Tuhan. Remaja teladan harus menjaga kesehatan dan menjauhi segala bentuk narkoba. Katakan TIDAK untuk narkoba, YES untuk Yesus'),\n(17, 'KEPRIBADIAN (Love, Sex, Dating)', 'Bagaimana cara menjadi pribadi yang disiplin sebagai remaja?', 'Membuat jadwal harian, menepati waktu, menyelesaikan tugas tepat waktu, bangun pagi untuk berdoa dan baca Alkitab, serta konsisten dalam komitmen', 'Disiplin adalah jembatan antara tujuan dan pencapaian. Remaja teladan yang disiplin akan sukses dalam studi, pelayanan, dan kehidupan sehari-hari'),\n(18, 'KEPRIBADIAN (Love, Sex, Dating)', 'Apa arti "menjadi teladan dalam kesucian"?', 'Menjaga pikiran, perkataan, dan perbuatan dari hal-hal yang najis, berpakaian sopan, tidak bergaul dengan lawan jenis secara berlebihan, dan hidup kudus', '1 Petrus 1:16 - Kuduslah kamu, sebab Aku kudus. Kesucian adalah pembeda antara anak-anak Tuhan dengan dunia. Remaja teladan harus memancarkan kekudusan'),\n(19, 'KEPRIBADIAN (Love, Sex, Dating)', 'Bagaimana remaja teladan menghadapi bullying/perundungan?', 'Tidak membalas dengan kekerasan, melaporkan kepada guru/orang tua, tetap percaya diri, mendoakan pelaku, dan mencari dukungan dari sahabat yang positif', 'Roma 12:21 - Janganlah kamu dikalahkan oleh kejahatan, tetapi kalahkanlah kejahatan dengan kebaikan. Remaja teladan adalah pembawa damai'),\n(20, 'KEPRIBADIAN (Love, Sex, Dating)', 'Apa yang harus dilakukan jika merasa jenuh dengan kegiatan rohani?', 'Evaluasi diri, cari cara baru untuk beribadah, libatkan diri dalam pelayanan aktif, curhat kepada pembina rohani, dan ingat kembali panggilan sebagai remaja Kristus', 'Rasa jenuh adalah normal. Remaja teladan harus terus mencari wajah Tuhan dan menemukan sukacita dalam kebersamaan dengan Tuhan. Jangan tinggalkan ibadah'),\n(21, 'PENGETAHUAN ALKITAB', 'Ceritakan keteladanan Daniel dalam hidup di tengah tekanan dunia!', 'Daniel berani tidak menajiskan diri dengan makanan raja, tetap berdoa 3 kali sehari meski dilarang, setia kepada Tuhan meski diancam masuk gua singa', 'Daniel menunjukkan bahwa iman tidak bisa dikompromikan. Ia tetap setia meski konsekuensinya berat. Tuhan melindungi Daniel karena kesetiaannya'),\n(22, 'PENGETAHUAN ALKITAB', 'Apa makna "Jangan menjadi serupa dengan dunia ini" (Roma 12:2)?', 'Jangan mengikuti gaya hidup, nilai, dan pola pikir dunia yang bertentangan dengan Firman Tuhan, tetapi terus diubahkan oleh Roh Kudus', 'Dunia mendorong egoisme, materialisme, dan dosa. Remaja teladan harus memiliki cara berpikir yang berbeda berdasarkan kebenaran Alkitab'),\n(23, 'PENGETAHUAN ALKITAB', 'Siapakah 3 tokoh remaja dalam Alkitab dan keteladanannya?', '1) Daud - berani melawan Goliat karena percaya Tuhan; 2) Timotius - menjadi teladan sekalipun muda; 3) Maria - menerima panggilan Tuhan dengan kerendahan hati', 'Mereka menunjukkan bahwa usia muda bukan halangan untuk dipakai Tuhan. Yang Tuhan lihat adalah hati yang taat dan beriman'),\n(24, 'PENGETAHUAN ALKITAB', 'Jelaskan isi Amanat Agung (Matius 28:19-20)!', 'Pergi, jadikan semua bangsa murid Kristus, baptis mereka dalam nama Bapa, Anak, dan Roh Kudus, serta ajarkan mereka melakukan semua perintah Yesus', 'Amanat Agung adalah mandat utama gereja. Setiap remaja teladan adalah missioner yang dipanggil untuk bersaksi di sekolah, keluarga, dan masyarakat'),\n(25, 'PENGETAHUAN ALKITAB', 'Apa arti dari perumpamaan "Talenta" (Matius 25:14-30)?', 'Setiap orang diberi karunia oleh Tuhan sesuai kemampuan. Kita harus mengembangkan dan menggunakan talenta untuk kemuliaan Tuhan, bukan menyembunyikannya', 'Talenta bukan hanya uang tetapi semua karunia: waktu, kemampuan, harta, kesehatan. Remaja teladan harus menjadi pengelola yang baik atas talenta Tuhan'),\n(26, 'PENGETAHUAN ALKITAB', 'Siapakah yang menulis kitab Mazmur dan apa tujuannya?', 'Daud dan para pemazmur lainnya menulis kitab Mazmur sebagai kumpulan nyanyian dan doa untuk ibadah, mengungkapkan sukacita, kesedihan, pertobatan, dan pujian kepada Tuhan', 'Mazmur adalah buku doa umat Tuhan. Setiap remaja teladan bisa belajar berkomunikasi dengan Tuhan melalui Mazmur dalam suka dan duka'),\n(27, 'PENGETAHUAN ALKITAB', 'Jelaskan kisah Yusuf dan keteladanannya!', 'Yusuf dijual oleh saudaranya, difitnah, dipenjara, tetapi tetap setia kepada Tuhan. Ia mengampuni saudaranya dan menjadi penguasa di Mesir yang menyelamatkan banyak orang', 'Yusuf tidak pernah membalas kejahatan dengan kejahatan. Ia percaya bahwa Tuhan bekerja dalam segala hal untuk kebaikan. Keteladanan: setia, pengampunan, integritas'),\n(28, 'PENGETAHUAN ALKITAB', 'Apa inti dari Sepuluh Perintah Allah (Keluaran 20)?', 'Perintah untuk mengasihi Tuhan (1-4) dan mengasihi sesama manusia (5-10). Semua perintah bertujuan untuk melindungi hubungan vertikal dan horizontal', 'Hukum Taurat diberikan untuk menunjukkan standar kekudusan Tuhan. Namun keselamatan adalah oleh iman, bukan karena melakukan hukum'),\n(29, 'PENGETAHUAN ALKITAB', 'Siapakah pahlawan iman dalam Ibrani 11? Sebutkan 5!', '1) Abraham - bapa orang percaya; 2) Musa - memilih menderita bersama umat Allah; 3) Daud - raja setelah hati Tuhan; 4) Samuel - nabi yang setia; 5) Rahab - percaya pada Tuhan Israel', 'Mereka semua belum menerima janji tetapi percaya dan taat. Iman adalah dasar dari segala sesuatu yang diharapkan dan bukti dari segala sesuatu yang tidak dilihat'),\n(30, 'PENGETAHUAN ALKITAB', 'Jelaskan tentang "Karunia Roh" (1 Korintus 12)!', 'Karunia Roh adalah kemampuan khusus yang diberikan Roh Kudus kepada setiap orang percaya untuk melayani dan membangun tubuh Kristus, bukan untuk kesombongan', 'Setiap remaja teladan memiliki karunia unik. Tidak ada karunia yang lebih hebat dari yang lain. Semua karunia harus digunakan dalam kasih'),\n(31, 'PENGETAHUAN ALKITAB', 'Apa isi pokok dari Khotbah di Bukit (Matius 5-7)?', 'Ucapan bahagia, garam dan terang dunia, hukum Taurat yang digenapi, larangan marah, berzinah, bersumpah, membalas, mengasihi musuh, berdoa, puasa, dan membangun di atas batu karang', 'Ini adalah manifesto Kerajaan Allah. Remaja teladan harus hidup dengan nilai-nilai kerajaan yang berbeda dari dunia: rendah hati, murah hati, pembawa damai'),\n(32, 'PENGETAHUAN ALKITAB', 'Jelaskan perumpamaan "Anak yang Hilang" (Lukas 15)!', 'Ada anak bungsu yang minta warisan, pergi jauh, hidup dalam dosa, jatuh miskin, bertobat dan kembali ke bapa. Bapa menerimanya dengan sukacita', 'Menggambarkan kasih Bapa Surgawi yang selalu menanti pertobatan anak-anak-Nya. Setiap remaja yang tersesat bisa kembali dan diterima dengan sukacita'),\n(33, 'PENGETAHUAN ALKITAB', 'Siapakah yang disebut "Juru Selamat" dalam Alkitab dan apa karya-Nya?', 'Yesus Kristus adalah satu-satunya Juru Selamat dunia. Karya-Nya: mati di kayu salib menebus dosa manusia, bangkit pada hari ketiga, dan naik ke surga', 'Tidak ada nama lain di bawah sorga yang diberikan kepada manusia yang olehnya kita dapat diselamatkan (Kisah 4:12). Remaja teladan harus mengenal Yesus secara pribadi'),\n(34, 'PENGETAHUAN ALKITAB', 'Jelaskan tentang "Perjanjian Baru" yang dijanjikan dalam Yeremia 31:31-34!', 'Perjanjian baru adalah perjanjian yang ditulis dalam hati, bukan di atas loh batu. Allah akan mengampuni dosa dan menjadi Tuhan atas umat-Nya', 'Perjanjian baru digenapi dalam darah Yesus Kristus. Remaja teladan hidup dalam perjanjian baru: hubungan pribadi dengan Tuhan melalui Yesus'),\n(35, 'PENGETAHUAN ALKITAB', 'Bagaimana Yesus mengajarkan tentang doa dalam Matius 6?', 'Berdoa dengan tidak bertele-tele, jangan seperti orang munafik, berdoa dalam kamar tertutup, dan mengajarkan Doa Bapa Kami sebagai contoh doa yang benar', 'Doa bukan tentang panjangnya kata-kata tetapi ketulusan hati. Doa Bapa Kami mencakup: pujian, kerajaan Allah, kebutuhan sehari-hari, pengampunan, dan perlindungan'),\n(36, 'PENGETAHUAN ALKITAB', 'Apa arti "Salib" bagi orang percaya?', 'Salib adalah simbol pengorbanan Yesus untuk menebus dosa manusia, menunjukkan kasih Allah yang luar biasa, dan kemenangan atas maut', 'Galatia 6:14 - Aku bermegah dalam salib Tuhan kita Yesus Kristus. Salib adalah pusat iman Kristen. Remaja teladan harus memikul salib setiap hari'),\n(37, 'PENGETAHUAN ALKITAB', 'Jelaskan tentang "Roh Kudus" dan karya-Nya!', 'Roh Kudus adalah Pribadi ketiga Allah Tritunggal. Karya-Nya: menghibur, mengajar, menuntun, menginsafkan akan dosa, dan memberikan karunia rohani', 'Yohanes 16:13 - Roh Kebenaran akan memimpin kamu ke dalam seluruh kebenaran. Remaja teladan harus peka pada tuntunan Roh Kudus dalam hidup sehari-hari'),\n(38, 'PENGETAHUAN ALKITAB', 'Siapakah yang dimaksud dengan "Gembala yang Baik" (Yohanes 10)?', 'Yesus Kristus adalah Gembala yang Baik yang mengenal domba-domba-Nya, domba mendengar suara-Nya, dan Ia memberikan nyawa-Nya untuk domba-domba-Nya', 'Yesus bukan gembala upahan yang lari ketika serigala datang. Remaja teladan adalah domba yang mendengar suara Gembala dan mengikuti-Nya'),\n(39, 'PENGETAHUAN ALKITAB', 'Jelaskan tentang "Iman, Pengharapan, dan Kasih" (1 Korintus 13)!', 'Iman: percaya pada Tuhan; Pengharapan: menanti janji Tuhan; Kasih: yang paling utama dan terbesar karena kekal selamanya. Kasih adalah motivasi murni dalam pelayanan', 'Iman dan pengharapan akan berakhir ketika kita bertemu Tuhan, tetapi kasih tetap kekal. Remaja teladan harus melayani dalam kasih, bukan karena kewajiban'),\n(40, 'PENGETAHUAN ALKITAB', 'Apa pesan utama kitab Wahyu bagi remaja masa kini?', 'Tuhan Yesus akan datang kembali sebagai Raja segala raja. Remaja harus hidup dalam kesucian, setia, berani bersaksi, dan mempersiapkan diri menyambut kedatangan-Nya', 'Wahyu memberi pengharapan bahwa kebaikan akan menang. Remaja teladan tidak perlu takut karena kemenangan sudah pasti di dalam Kristus'),\n(41, 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Apa saja 2 Sakramen yang dilayankan GMIM?', 'Sakramen Baptisan Kudus dan Sakramen Perjamuan Kudus', 'Sakramen adalah tanda dan meterai dari perjanjian kasih karunia Allah. GMIM hanya melayankan 2 sakramen sesuai ajaran Reformasi'),\n(42, 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Jelaskan sistem "Presbiterial Sinodal" di GMIM!', 'Sistem di mana kepemimpinan dijalankan oleh para presbiter (penatua) secara kolektif, dan keputusan diambil melalui musyawarah mufakat dalam sidang di semua aras (Jemaat, Wilayah, Sinode)', 'Presbiterial = kepemimpinan kolektif para penatua; Sinodal = berjalan bersama. Remaja teladan harus menghargai proses musyawarah dan keputusan bersama'),\n(43, 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Kapan GMIM berdiri sendiri sebagai gereja mandiri?', '30 September 1934', 'GMIM berdiri sendiri dari Indische Kerk. Tanggal ini diperingati setiap tahun sebagai hari jadi GMIM. Remaja teladan harus bangga dan menjaga warisan gereja'),\n(44, 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Siapakah 2 misionaris utama yang memberitakan Injil di Minahasa?', 'J.G. Schwarz dan J.F. Riedel', 'Schwarz melayani di Langowan dan Kakas, Riedel di Tondano. Mereka datang pada abad ke-19. Remaja teladan belajar dari semangat pengorbanan mereka'),\n(45, 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Apa visi dan misi pelayanan Remaja GMIM?', 'Visi: "Remaja Bagi Kristus" (Teens for Christ). Misi: Menjadikan remaja GMIM yang berakar, bertumbuh, dan berbuah bagi Kristus', 'Visi ini adalah komitmen bahwa seluruh hidup remaja dipersembahkan bagi Kristus. Remaja teladan harus menghayati visi ini setiap hari'),\n(46, 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Jelaskan 3 aras pelayanan dalam GMIM!', '1) Aras Jemaat - tingkat lokal/persekutuan; 2) Aras Wilayah - gabungan beberapa jemaat; 3) Aras Sinode - tingkat pusat/seluruh GMIM', 'Setiap aras memiliki tugas dan tanggung jawab. Remaja teladan melayani di aras Jemaat, Wilayah, dan bisa berkontribusi di aras Sinode'),\n(47, 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Siapakah Ketua Sinode GMIM pertama?', 'Ds. E.A.A. de Vreede (1934-1935)', 'Beliau adalah misionaris Belanda yang memimpin GMIM pada awal berdirinya. Sejarah mencatat jasanya dalam menata gereja yang baru berdiri'),\n(48, 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Apa makna Lambang GMIM (Burung Manguni)?', 'Burung Manguni melambangkan gereja di tanah Minahasa yang menjadi terang di tengah kegelapan, karena Manguni beraktivitas di malam hari', 'Jumlah sayap (34) melambangkan tahun 1934, bulan September (sembilan helai sayap luar), dan tanggal 30 (lima kelopak daun). Remaja teladan harus memaknai lambang ini'),\n(49, 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Jelaskan tentang Komisi Pelayanan Remaja Sinode (KPRS)!', 'KPRS adalah perangkat pelayanan di aras Sinode yang mengoordinasikan pelayanan remaja di seluruh GMIM, termasuk Pemilihan Remaja Teladan, LKRG, PKRS, dan program lainnya', 'KPRS berdiri sendiri sejak 28 Januari 1990. Remaja teladan harus mendukung program KPRS dan aktif dalam kegiatan remaja'),\n(50, 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Apa isi Pengakuan Iman Rasuli?', 'Aku percaya kepada Allah Bapa yang mahakuasa, dan kepada Yesus Kristus Anak-Nya yang tunggal, dan kepada Roh Kudus, gereja yang kudus dan am, pengampunan dosa, kebangkitan daging, dan hidup kekal', 'Pengakuan Iman Rasuli adalah ringkasan iman Kristen yang diakui GMIM. Remaja teladan harus hafal dan memahami isinya'),\n(51, 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Sebutkan 3 tokoh penting dalam sejarah GMIM!', '1) Pdt. Dr. W.A. Roeroe - Ketua Sinode terlama; 2) Pdt. A.Z.R. Wenas - Ketua Sinode pribumi pertama; 3) Pnt. Ir. D.M. Rondonuwu - Pendiri dan penggerak KPRS', 'Mereka adalah teladan pengabdian. Remaja teladan belajar dari dedikasi dan komitmen mereka melayani Tuhan dan gereja'),\n(52, 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Jelaskan tentang "Tata Gereja GMIM"!', 'Tata Gereja adalah aturan dasar tentang pengakuan iman, panggilan, sistem, struktur, perangkat pelayanan, dan tata tertib dalam kehidupan bergereja di GMIM', 'Tata Gereja 2021 adalah yang berlaku sekarang. Remaja teladan wajib mengetahui aturan dasar gerejanya agar tidak tersesat dalam pengajaran'),\n(53, 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Apa perbedaan antara Diaken dan Penatua?', 'Diaken: melayani diakonia (pelayanan kasih dan pengelolaan keuangan). Penatua: melayani pemberitaan firman, ibadah, dan penggembalaan', 'Diaken dan Penatua adalah pelayan khusus. Remaja teladan dapat merindukan jabatan ini di kemudian hari (1 Timotius 3)'),\n(54, 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Siapakah Pendeta GMIM pertama yang menjadi Ketua Sinode?', 'Pdt. Rein Markus Luntungan (1967-1979)', 'Beliau adalah orang Minahasa pertama bergelar Pendeta yang memimpin GMIM. Sebelumnya Ketua Sinode adalah misionaris atau Guru Agama'),\n(55, 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Apa makna "Sitou Timou Tumou Tou" bagi GMIM?', '"Manusia hidup untuk memanusiakan manusia lain" - semboyan yang mencerminkan panggilan diakonia dan pelayanan sesama dalam semangat kasih Kristus', 'Semboyan ini diangkat dari falsafah Minahasa. Remaja teladan harus mewujudkannya dalam tindakan nyata melayani sesama'),\n(56, 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Jelaskan tentang Badan Pekerja Majelis Sinode (BPMS)!', 'BPMS adalah pimpinan tertinggi GMIM yang melaksanakan keputusan Sidang Majelis Sinode, dipilih setiap 5 tahun, bertanggung jawab atas pelayanan gereja secara menyeluruh', 'BPMS periode 2022-2027 berjumlah 13 orang. Remaja teladan mendoakan para pemimpin gereja agar diberi hikmat'),\n(57, 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Apa saja peraturan dalam Tata Gereja GMIM 2021?', 'Peraturan tentang: Jemaat, Wilayah, Sinode, Pelayan Khusus, Pekerja GMIM, Perbendaharaan, dan Penggembalaan, Penilikan, Disiplin Gerejawi', 'Ketujuh peraturan ini mengatur seluruh aspek kehidupan bergereja. Remaja teladan setidaknya memahami Peraturan tentang Jemaat khususnya pasal remaja'),\n(58, 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Kapan dan di mana Komisi Pelayanan Remaja Sinode (KPRS) berdiri sendiri?', '28 Januari 1990 di Palelon Modoinding, Wilayah Modoinding', 'Tanggal ini diperingati sebagai Hari Persatuan Remaja GMIM. Remaja teladan harus merayakan dan memaknai sejarah perjuangan pelayanan remaja'),\n(59, 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Siapakah penginjil yang dijuluki "Rasul Maluku" dan datang ke Minahasa tahun 1817?', 'Johann Friedrich Riedel (bukan J.P. Riedel yang lebih dikenal)', 'Ia memulai pekabaran Injil di Minahasa setelah sebelumnya melayani di Maluku. Remaja teladan bersyukur atas jerih lelah para penginjil'),\n(60, 'AJARAN, TATA GEREJA & SEJARAH GMIM', 'Jelaskan tentang "LKRG" (Latihan Kader Remaja Gereja)!', 'LKRG adalah program pembinaan KPRS untuk mempersiapkan remaja menjadi kader yang militan, berkarakter Kristus, dan memiliki spiritualitas yang kuat', 'LKRG terdiri dari tingkat Dasar, Madya, dan Taruna. Remaja teladan harus mengikuti LKRG sebagai bekal pelayanan ke depan'),\n(61, 'KEPEMIMPINAN DAN ORGANISASI', 'Sebutkan 5 karakter pemimpin Kristen yang baik!', '1) Hamba (melayani bukan dilayani); 2) Rendah hati; 3) Berintegritas; 4) Berani mengambil keputusan; 5) Mengasihi yang dipimpin', 'Yesus adalah teladan pemimpin sempurna (Markus 10:45). Remaja teladan harus mengembangkan karakter ini sejak dini'),\n(62, 'KEPEMIMPINAN DAN ORGANISASI', 'Bagaimana cara menjadi pemimpin remaja yang efektif?', 'Mendengar aspirasi anggota, memimpin dengan teladan, komunikatif, tidak otoriter, menghargai setiap anggota, dan selalu mengutamakan Tuhan dalam setiap keputusan', 'Kepemimpinan bukan tentang jabatan tetapi pengaruh. Remaja teladan yang efektif melayani, bukan memerintah'),\n(63, 'KEPEMIMPINAN DAN ORGANISASI', 'Jelaskan gaya kepemimpinan Yesus Kristus!', 'Kepemimpinan hamba (Servant Leadership): membasuh kaki murid, mengutamakan kebutuhan orang lain, rela berkorban, dan memberdayakan murid-murid-Nya', 'Inilah gaya kepemimpinan yang revolusioner. Remaja teladan harus meneladani Yesus yang datang untuk melayani, bukan untuk dilayani'),\n(64, 'KEPEMIMPINAN DAN ORGANISASI', 'Bagaimana cara menyelesaikan konflik dalam organisasi remaja?', 'Dengarkan kedua belah pihak, cari fakta, mediasi secara netral, dorong musyawarah, cari solusi win-win, doakan masalah bersama, dan rekonsiliasi', 'Matius 18:15-17 memberikan prosedur penyelesaian konflik. Remaja teladan harus menjadi pembawa damai (peacemaker)'),\n(65, 'KEPEMIMPINAN DAN ORGANISASI', 'Apa pentingnya organisasi bagi remaja GMIM?', 'Wadah pengembangan diri, tempat belajar kepemimpinan, sarana bersekutu dan bersaksi, melatih tanggung jawab, serta mempersiapkan kader penerus gereja', 'Organisasi bukan tujuan akhir tetapi alat mencapai visi. Remaja teladan harus aktif berorganisasi untuk mengasah kemampuan'),\n(66, 'KEPEMIMPINAN DAN ORGANISASI', 'Bagaimana cara memotivasi anggota remaja yang malas?', 'Pendekatan personal, cari tahu penyebab kemalasannya, beri tanggung jawab kecil, beri apresiasi, libatkan dalam pengambilan keputusan, dan doakan', 'Setiap orang unik. Remaja teladan harus sabar dan bijak memotivasi, bukan memaksa. Kasih yang tulus akan menggerakkan hati'),\n(67, 'KEPEMIMPINAN DAN ORGANISASI', 'Jelaskan perbedaan antara pemimpin dan bos!', 'Pemimpin: mengayomi, melayani, memberi contoh, mendengar, menginspirasi. Bos: memerintah, menuntut, otoriter, mencari keuntungan sendiri', 'Pemimpin membawa perubahan positif. Remaja teladan harus menjadi pemimpin yang dirindukan, bukan bos yang ditakuti'),\n(68, 'KEPEMIMPINAN DAN ORGANISASI', 'Bagaimana cara melakukan rapat organisasi yang efektif?', 'Buat agenda jelas, tepat waktu, pimpin diskusi terarah, libatkan semua anggota, buat notulen, tindak lanjuti keputusan, dan evaluasi', 'Rapat bukan ajang adu argumen tetapi mencari kehendak Tuhan bersama. Remaja teladan harus memimpin rapat dengan bijak'),\n(69, 'KEPEMIMPINAN DAN ORGANISASI', 'Apa yang dimaksud dengan "delegasi tugas" dalam organisasi?', 'Pemberian wewenang dan tanggung jawab kepada anggota lain untuk melaksanakan tugas tertentu, disertai pengawasan dan bimbingan, tanpa melepas tanggung jawab akhir', 'Delegasi melatih orang lain dan mencegah burnout pemimpin. Remaja teladan harus belajar mendelegasi dengan bijak dan percaya pada tim'),\n(70, 'KEPEMIMPINAN DAN ORGANISASI', 'Bagaimana cara mengelola waktu sebagai pemimpin remaja?', 'Buat skala prioritas (penting-mendesak), buat jadwal harian, hindari prokrastinasi, belajar mengatakan "tidak" pada hal yang tidak penting, dan sisihkan waktu untuk Tuhan', 'Waktu adalah anugerah Tuhan. Remaja teladan adalah pengelola waktu yang baik (time management) agar seimbang dalam studi, pelayanan, dan istirahat'),\n(71, 'KEPEMIMPINAN DAN ORGANISASI', 'Sebutkan 3 tantangan utama pemimpin remaja saat ini!', '1) Pengaruh negatif media sosial dan teknologi; 2) Pergaulan bebas dan narkoba; 3) Keterbatasan waktu antara studi dan pelayanan', 'Remaja teladan harus sadar akan tantangan dan mencari strategi mengatasinya dengan iman dan kreativitas'),\n(72, 'KEPEMIMPINAN DAN ORGANISASI', 'Bagaimana cara membangun tim kerja yang solid?', 'Memiliki visi yang sama, komunikasi terbuka, saling percaya, menghargai perbedaan, merayakan keberhasilan bersama, dan menyelesaikan konflik secara dewasa', 'Tim yang solid tidak terjadi secara instan. Remaja teladan harus membangun kebersamaan melalui kegiatan bersama dan doa'),\n(73, 'KEPEMIMPINAN DAN ORGANISASI', 'Apa arti "Kepemimpinan Transformasional" dalam konteks remaja?', 'Kepemimpinan yang membawa perubahan positif pada diri anggota (transformasi karakter) bukan hanya pencapaian target. Pemimpin menginspirasi dan memberdayakan', 'Bukan sekadar mengganti program tetapi mengubahkan hidup. Remaja teladan harus menjadi agen transformasi bagi teman-temannya'),\n(74, 'KEPEMIMPINAN DAN ORGANISASI', 'Bagaimana cara menghadapi kritik sebagai pemimpin?', 'Dengarkan dengan hati terbuka, jangan defensif, evaluasi apakah kritik membangun, minta maaf jika salah, dan gunakan kritik untuk perbaikan diri', 'Amsal 15:31 - Orang yang mengindahkan teguran yang membawa kehidupan akan mendapat tempat di antara orang bijak. Kritik adalah hadiah tersembunyi'),\n(75, 'KEPEMIMPINAN DAN ORGANISASI', 'Jelaskan pentingnya "Pembinaan" dalam organisasi remaja!', 'Pembinaan adalah proses pendampingan untuk mengembangkan potensi anggota, memperkuat iman, mengajarkan nilai-nilai Kristus, dan mempersiapkan regenerasi kepemimpinan', 'Pembinaan mencegah kepunahan organisasi. Remaja teladan harus bersedia dibina dan kemudian menjadi pembina bagi adik-adiknya'),\n(76, 'KEPEMIMPINAN DAN ORGANISASI', 'Bagaimana cara mengambil keputusan dalam organisasi secara bijak?', 'Doa dan puasa, kumpulkan data dan fakta, libatkan tim, musyawarah, pertimbangkan dampak jangka pendek dan panjang, dan berani mengambil keputusan', 'Yakobus 1:5 - Jika ada yang kekurangan hikmat, hendaklah ia memintakannya kepada Allah. Remaja teladan tidak boleh mengambil keputusan sendirian'),\n(77, 'KEPEMIMPINAN DAN ORGANISASI', 'Apa perbedaan antara "pemimpin karismatik" dan "pemimpin hamba"?', 'Pemimpin karismatik: mengandalkan daya tarik pribadi; Pemimpin hamba: mengandalkan kasih dan pelayanan. Pemimpin hamba lebih berkelanjutan karena berpusat pada Kristus', 'Karisma tanpa karakter berbahaya. Remaja teladan harus mengejar karakter Kristus, bukan sekadar popularitas'),\n(78, 'KEPEMIMPINAN DAN ORGANISASI', 'Bagaimana cara mengembangkan bakat kepemimpinan?', 'Belajar dari pemimpin yang baik, membaca buku kepemimpinan, praktik memimpin kelompok kecil, minta mentoring, dan evaluasi diri secara rutin', 'Kepemimpinan bisa dipelajari. Remaja teladan harus proaktif mengembangkan diri, bukan menunggu ditunjuk'),\n(79, 'KEPEMIMPINAN DAN ORGANISASI', 'Apa yang harus dilakukan jika program kerja gagal?', 'Evaluasi penyebab kegagalan, jangan saling menyalahkan, belajar dari kesalahan, revisi program, libatkan tim dalam solusi, dan tetap semangat', 'Kegagalan adalah guru terbaik. Remaja teladan tidak berkecil hati tetapi bangkit kembali (Proverbs 24:16 - orang benar jatuh 7 kali tetapi bangkit kembali)'),\n(80, 'KEPEMIMPINAN DAN ORGANISASI', 'Bagaimana cara mewariskan kepemimpinan kepada generasi berikutnya?', 'Membuat sistem kaderisasi, memberi kesempatan anggota muda memimpin, mentoring intensif, dokumentasi best practice, dan doa bersama untuk regenerasi', 'Pemimpin hebat meninggalkan pewaris, bukan kekosongan. Remaja teladan harus mempersiapkan pengganti sebelum masa jabatan berakhir'),\n(81, 'PENGETAHUAN UMUM', 'Siapakah Presiden ke-7 Republik Indonesia?', 'Joko Widodo (Jokowi)', 'Beliau menjabat sejak 2014 hingga 2024. Remaja teladan harus menghormati pemimpin negara dan mendoakannya'),\n(82, 'PENGETAHUAN UMUM', 'Sebutkan 5 negara pendiri ASEAN!', 'Indonesia, Malaysia, Filipina, Singapura, Thailand (5 negara) ditambah Brunei kemudian', 'ASEAN didirikan 8 Agustus 1967 di Bangkok. Remaja teladan sebagai warga ASEAN harus memahami kerjasama regional ini'),\n(83, 'PENGETAHUAN UMUM', 'Apa kepanjangan dari PBB?', 'Perserikatan Bangsa-Bangsa (United Nations)', 'PBB didirikan 24 Oktober 1945. Remaja teladan harus peduli pada perdamaian dunia sesuai panggilan gereja universal'),\n(84, 'PENGETAHUAN UMUM', 'Siapakah penemu lampu listrik?', 'Thomas Alva Edison', 'Penemuan ini mengubah peradaban dunia. Remaja teladan harus menghargai sains dan teknologi sebagai anugerah Tuhan'),\n(85, 'PENGETAHUAN UMUM', 'Apa ibu kota negara Jepang?', 'Tokyo', 'Tokyo juga menjadi tuan rumah Olimpiade 2020. Remaja teladan perlu pengetahuan geografi dunia untuk memperluas wawasan'),\n(86, 'PENGETAHUAN UMUM', 'Siapakah pahlawan proklamator Indonesia?', 'Ir. Soekarno dan Drs. Mohammad Hatta', 'Mereka membacakan teks proklamasi 17 Agustus 1945. Remaja teladan harus meneladani semangat nasionalisme mereka'),\n(87, 'PENGETAHUAN UMUM', 'Apa gunung tertinggi di dunia?', 'Gunung Everest (8.848 mdpl)', 'Terletak di Nepal/Tibet. Remaja teladan belajar tentang keajaiban ciptaan Tuhan yang luar biasa'),\n(88, 'PENGETAHUAN UMUM', 'Sebutkan 5 agama yang diakui di Indonesia!', 'Islam, Kristen, Katolik, Hindu, Buddha (Konghucu juga diakui)', 'Indonesia adalah negara Bhinneka Tunggal Ika. Remaja teladan harus hidup rukun dalam perbedaan'),\n(89, 'PENGETAHUAN UMUM', 'Siapa presiden pertama Amerika Serikat?', 'George Washington', 'Ia memimpin perang kemerdekaan AS. Remaja teladan belajar dari sejarah kepemimpinan dunia'),\n(90, 'PENGETAHUAN UMUM', 'Apa nama samudera terluas di dunia?', 'Samudera Pasifik', 'Mencakup sekitar 1/3 permukaan bumi. Remaja teladan takjub akan kebesaran Tuhan Sang Pencipta'),\n(91, 'PENGETAHUAN UMUM', 'Kapan Indonesia merdeka?', '17 Agustus 1945', 'Kemerdekaan adalah anugerah Tuhan. Remaja teladan harus mengisi kemerdekaan dengan hal-hal positif dan membangun bangsa'),\n(92, 'PENGETAHUAN UMUM', 'Siapa penulis novel "Laskar Pelangi"?', 'Andrea Hirata', 'Novel ini menginspirasi tentang semangat belajar anak-anak Belitung. Remaja teladan harus rajin membaca dan berkarya'),\n(93, 'PENGETAHUAN UMUM', 'Apa kepanjangan dari UNESCO?', 'United Nations Educational, Scientific and Cultural Organization', 'Badan PBB untuk pendidikan, sains, dan budaya. Remaja teladan mendukung misi pendidikan dan pelestarian budaya'),\n(94, 'PENGETAHUAN UMUM', 'Siapa peraih Nobel Perdamaian asal Indonesia?', 'Dr. Jose Ramos-Horta (Timor Leste) dan juga tokoh lain', 'Remaja teladan belajar bahwa perdamaian dunia dimulai dari diri sendiri dan lingkungan sekitar'),\n(95, 'PENGETAHUAN UMUM', 'Apa mata uang negara Inggris?', 'Pound Sterling (£)', 'Inggris adalah negara kerajaan. Remaja teladan perlu pengetahuan ekonomi global'),\n(96, 'PENGETAHUAN UMUM', 'Siapa penemu teori relativitas?', 'Albert Einstein', 'Fisikawan Jerman ini mengubah pemahaman tentang ruang dan waktu. Remaja teladan mengembangkan kemampuan sains untuk kemuliaan Tuhan'),\n(97, 'PENGETAHUAN UMUM', 'Sebutkan 5 benua di dunia!', 'Asia, Afrika, Amerika, Eropa, Australia (Antartika juga benua)', 'Remaja teladan harus memiliki wawasan global sebagai warga dunia yang dipanggil menjadi terang'),\n(98, 'PENGETAHUAN UMUM', 'Apa nama tarian tradisional dari Minahasa?', 'Tari Maengket', 'Tarian ini menggambarkan sukacita panen. Remaja teladan harus melestarikan budaya daerah sebagai kekayaan bangsa'),\n(99, 'PENGETAHUAN UMUM', 'Siapa gubernur Sulawesi Utara periode 2024-2029?', '(Sesuaikan dengan fakta saat ujian) Yulius Selvanus (setelah Pilkada 2024)', 'Remaja teladan harus mengenal pemimpin daerahnya untuk dapat berkolaborasi dalam pembangunan'),\n(100, 'PENGETAHUAN UMUM', 'Apa lambang negara Indonesia?', 'Burung Garuda Pancasila', 'Dengan semboyan "Bhinneka Tunggal Ika". Remaja teladan harus menghormati lambang negara sebagai identitas bangsa'),\n(101, 'KEREMAJAAN GMIM', 'Apa visi pelayanan remaja GMIM?', '"Remaja Bagi Kristus" (Teens for Christ)', 'Semua program dan kegiatan remaja diarahkan untuk memuliakan Kristus. Remaja teladan harus menghayati visi ini dalam hidup sehari-hari'),\n(102, 'KEREMAJAAN GMIM', 'Apa saja program unggulan KPRS GMIM?', 'LKRG, Pemilihan Remaja Teladan, PKRS (Perkemahan Kreatif Remaja Sinode), HPRG (Hari Persatuan Remaja GMIM), PSR (Pesta Seni Remaja)', 'Program-program ini membina dan mengembangkan potensi remaja. Remaja teladan harus berpartisipasi aktif dalam kegiatan ini'),\n(103, 'KEREMAJAAN GMIM', 'Jelaskan tentang LKRG (Latihan Kader Remaja Gereja)!', 'LKRG adalah pembinaan berjenjang untuk mempersiapkan remaja menjadi kader gereja yang militan, memiliki spiritualitas kuat, dan mampu melayani', 'Ada 3 tingkat: Dasar, Madya, Taruna. Remaja teladan harus mengikuti LKRG sebagai bekal pelayanan di masa depan'),\n(104, 'KEREMAJAAN GMIM', 'Kapan Hari Persatuan Remaja GMIM diperingati?', '28 Januari setiap tahun', 'Memperingati berdirinya Komisi Pelayanan Remaja Sinode GMIM yang mandiri pada 1990. Remaja teladan merayakannya dengan sukacita'),\n(105, 'KEREMAJAAN GMIM', 'Apa model remaja GMIM yang diharapkan berdasarkan Lukas 2:52?', 'Remaja yang bertumbuh dalam 4 aspek: fisik, intelektual, spiritual, dan sosial', 'Yesus sendiri menunjukkan pertumbuhan yang seimbang. Remaja teladan harus berusaha berkembang dalam semua aspek'),\n(106, 'KEREMAJAAN GMIM', 'Sebutkan 5 Bidang dalam KPRS GMIM periode 2022-2027!', '1) P3SDM, 2) APIM, 3) PMB, 4) LITBANG, 5) TIK, dan bidang lainnya', 'Setiap bidang memiliki tugas spesifik. Remaja teladan dapat berkontribusi sesuai bidang minatnya'),\n(107, 'KEREMAJAAN GMIM', 'Apa kepanjangan dari KB3?', 'Komunitas Berakar, Bertumbuh, Berbuah', 'Program pemuridan remaja GMIM yang membina remaja dalam kelompok kecil untuk bertumbuh dalam iman'),\n(108, 'KEREMAJAAN GMIM', 'Siapa pencipta lagu "Menjadi Teladan"?', 'Pnt. Ir. Dwight Moody Rondonuwu, MT', 'Lagu ini dinyanyikan pertama kali pada Pemilihan Remaja Teladan tahun 2015. Remaja teladan harus hafal dan menginternalisasi liriknya'),\n(109, 'KEREMAJAAN GMIM', 'Jelaskan tentang Pemilihan Remaja Teladan GMIM!', 'Ajang seleksi remaja GMIM yang memiliki kriteria teladan dalam iman, pengetahuan, kepribadian, dan potensi diri melalui beberapa tahapan: tes tertulis, wawancara, karantina, pelayanan holistik, kompetisi potensi diri, dan grand final', 'Tujuannya mendapatkan remaja teladan yang menjadi contoh bagi remaja lainnya. Remaja teladan yang terpilih memiliki tanggung jawab besar'),\n(110, 'KEREMAJAAN GMIM', 'Apa makna "berakar, bertumbuh, dan berbuah" bagi remaja?', 'Berakar: memiliki dasar iman yang kuat dalam Kristus; Bertumbuh: terus berkembang dalam karakter dan pengetahuan; Berbuah: membawa dampak positif bagi orang lain', 'Ini adalah proses rohani yang berkelanjutan. Remaja teladan harus terus berproses menuju kedewasaan penuh dalam Kristus'),\n(111, 'KEREMAJAAN GMIM', 'Siapakah ketua KPRS GMIM periode 2022-2027?', 'Pnt. dr. Michaela E. Paruntu, MARS', 'Beliau memimpin pelayanan remaja di aras sinode. Remaja teladan harus mendukung dan mendoakan kepemimpinan beliau'),\n(112, 'KEREMAJAAN GMIM', 'Sebutkan 12 Rayon pelayanan KPRS GMIM!', 'Rayon: Manado, Bitung, Minahasa Utara, Minahasa, Minahasa Selatan, Minahasa Tenggara, Bolmong, Bolmong Selatan, Bolmong Timur, Kotamobagu, Sangihe, Talaud (atau sesuai data terbaru)', 'Pembagian rayon memudahkan koordinasi pelayanan. Remaja teladan mengenal rayonnya masing-masing'),\n(113, 'KEREMAJAAN GMIM', 'Apa itu SIKAT?', 'Sistem Informasi Kegiatan Terpadu - sistem online untuk pendaftaran kegiatan remaja GMIM (Pemilihan Remaja Teladan, PSR, dll)', 'Teknologi memudahkan pelayanan. Remaja teladan harus melek digital dan memanfaatkan SIKAT dengan baik'),\n(114, 'KEREMAJAAN GMIM', 'Jelaskan tentang "Gerakan Membaca Alkitab Remaja (GEMAR)"!', 'Program KPRS yang mendorong remaja membaca Alkitab secara terstruktur dan berkelanjutan untuk meningkatkan pengetahuan Alkitab', 'GEMAR dikelola Bidang APIM. Remaja teladan harus menjadi duta gerakan membaca Alkitab'),\n(115, 'KEREMAJAAN GMIM', 'Siapa yang dapat menjadi peserta Pemilihan Remaja Teladan?', 'Remaja GMIM usia 12-16 tahun 364 hari, sehat jasmani rohani, berprestasi akademik, berwawasan luas, dan berkelakuan baik', 'Persyaratan ini memastikan kualitas peserta. Remaja teladan harus memenuhi kriteria ini'),\n(116, 'KEREMAJAAN GMIM', 'Apa itu PKRS (Perkemahan Kreatif Remaja Sinode)?', 'Perkemahan tahunan remaja GMIM yang berisi pembinaan, pelatihan, perlombaan, dan persekutuan antar remaja se-Sinode', 'Tempat membangun persaudaraan dan mengembangkan potensi. Remaja teladan harus mengikuti PKRS untuk memperluas pergaulan'),\n(117, 'KEREMAJAAN GMIM', 'Sebutkan lagu-lagu wajib dalam kegiatan remaja GMIM!', 'Mars Remaja GMIM, Menjadi Teladan, Bangkitlah Pemuda-Pemudi, Lagu KPRS, dan lagu rohani lainnya', 'Lagu-lagu ini membangun semangat kebersamaan. Remaja teladan harus hafal dan dapat menyanyikannya'),\n(118, 'KEREMAJAAN GMIM', 'Apa peran Pembina Remaja dalam pelayanan remaja?', 'Membimbing, mengarahkan, melatih, menjadi teladan, dan mendampingi remaja dalam setiap kegiatan pelayanan', 'Pembina Remaja adalah ujung tombak pembinaan. Remaja teladan harus menghormati dan mendengarkan nasihat pembina'),\n(119, 'KEREMAJAAN GMIM', 'Bagaimana cara menjadi Remaja Teladan yang baik?', 'Memiliki iman yang kuat, pengetahuan Alkitab yang baik, karakter yang terpuji, prestasi akademik, aktif dalam pelayanan, dan menjadi berkat bagi orang lain', 'Ini adalah proses seumur hidup. Remaja teladan tidak pernah berhenti belajar dan bertumbuh'),\n(120, 'KEREMAJAAN GMIM', 'Apa pesan Anda untuk remaja GMIM masa kini?', 'Tetaplah setia kepada Tuhan di tengah tantangan zaman, jadilah terang di sekolah dan masyarakat, bangun persaudaraan sejati, dan persiapkan diri menjadi pemimpin masa depan gereja', 'Masa depan gereja ada di tangan remaja hari ini. Remaja teladan harus bangkit dan mengambil peran'),\n(121, 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Sebutkan 5 destinasi wisata unggulan di Sulawesi Utara!', '1) Bunaken (laut dan terumbu karang); 2) Gunung Mahawu (pendakian); 3) Danau Tondano; 4) Bukit Kasih Kanonang; 5) Pantai Paal Beach Likupang', 'Sulut kaya akan keindahan alam. Remaja teladan harus bangga dan ikut mempromosikan pariwisata daerah'),\n(122, 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Apa makna tari Maengket bagi masyarakat Minahasa?', 'Tarian tradisional yang menggambarkan rasa syukur atas hasil panen dan sukacita masyarakat Minahasa, biasanya ditarikan pada acara adat dan syukuran', 'Melestarikan budaya adalah bagian dari identitas. Remaja teladan harus belajar dan melestarikan tarian tradisional'),\n(123, 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Translate to English: "Remaja teladan harus berkelakuan baik"', '"An exemplary youth must behave well" atau "A role model teenager should have good conduct"', 'Penguasaan Bahasa Inggris penting untuk komunikasi global. Remaja teladan harus berlatih berbicara dalam Bahasa Inggris'),\n(124, 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Sebutkan 3 makanan khas Minahasa!', '1) Tinutuan (bubur manado); 2) RW (Rica-rica-Woku); 3) Paniki (masakan kelelawar); 4) Klappertaart; 5) Klapertart', 'Kuliner adalah kekayaan budaya. Remaja teladan bisa mempromosikan makanan khas daerah melalui media sosial'),\n(125, 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'What is the English word for "Bunaken"?', 'Bunaken (proper noun, tetap Bunaken) - it is a famous marine park in North Sulawesi', 'Remaja teladan harus mampu menjelaskan destinasi wisata Sulut dalam Bahasa Inggris kepada wisatawan asing'),\n(126, 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Apa upacara adat yang terkenal di Minahasa?', 'Upacara "Mapalus" (gotong royong) dan "Tumoutou" (upacara adat kelahiran/gelar adat)', 'Nilai-nilai luhur budaya harus dijaga. Remaja teladan mengamalkan semangat Mapalus dalam pelayanan'),\n(127, 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Translate: "I want to be a role model teenager in my church"', '"Aku ingin menjadi remaja teladan di gerejaku"', 'Kemampuan menerjemahkan membantu pemahaman lintas budaya. Remaja teladan harus menguasai kedua bahasa'),\n(128, 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Sebutkan 3 bahasa daerah di Sulawesi Utara!', '1) Bahasa Minahasa (Tombulu, Tondano, Tonsawang, dll); 2) Bahasa Bolaang Mongondow; 3) Bahasa Sangihe; 4) Bahasa Talaud', 'Setiap daerah memiliki bahasa unik. Remaja teladan harus bisa berbahasa daerah minimal untuk berkomunikasi dengan orang tua'),\n(129, 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'What is the English word for "keteladanan"?', '"Exemplary" atau "Role model" atau "Good example"', 'Remaja teladan harus menghafal kosakata Bahasa Inggris yang sering muncul dalam wawancara'),\n(130, 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Apa yang dimaksud dengan "Bunaken National Park"?', 'Taman Laut Nasional di Sulawesi Utara yang terkenal dengan keanekaragaman hayati laut, spot diving kelas dunia, dan menjadi kebanggaan Indonesia', 'Bunaken adalah warisan dunia. Remaja teladan harus ikut menjaga kelestarian taman laut ini'),\n(131, 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Sebutkan 3 alat musik tradisional Minahasa!', '1) Kolintang; 2) Tumatenden (seperti gong); 3) Popondi (alat musik tiup); 4) Suling Minahasa', 'Kolintang bahkan sudah diakui UNESCO. Remaja teladan harus bisa memainkan atau setidaknya mengenal alat musik tradisional'),\n(132, 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Translate: "The exemplary youth must be faithful in small things"', '"Remaja teladan harus setia dalam hal-hal kecil"', 'Peribahasa ini mengajarkan integritas. Remaja teladan memahami bahwa kesetiaan dalam hal kecil membawa kepada hal besar'),\n(133, 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Apa nama rumah adat Minahasa?', '"Wale" atau "Rumah Pewaris" (dengan bentuk panggung dan atap tinggi)', 'Rumah adat mencerminkan kearifan lokal. Remaja teladan harus melestarikan arsitektur tradisional'),\n(134, 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'How do you say "Terima kasih" in English?', '"Thank you"', 'Ungkapan sopan santun ini penting dalam komunikasi. Remaja teladan harus selalu mengucapkan terima kasih dalam kedua bahasa'),\n(135, 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Sebutkan 3 event wisata tahunan di Sulawesi Utara!', '1) Festival Likupang; 2) Sail Tomini; 3) Festival Danau Tondano; 4) Lomba Perahu Traditional Bunaken', 'Event ini menarik wisatawan. Remaja teladan bisa menjadi relawan atau duta wisata dalam event tersebut'),\n(136, 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'What is the meaning of "Sitou Timou Tumou Tou" in English?', '"Humans live to humanize other humans" atau "Man lives to give life to others"', 'Ini adalah falsafah hidup orang Minahasa. Remaja teladan harus menghayatinya dalam pelayanan diakonia'),\n(137, 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Apa senjata tradisional Minahasa?', '"Parang" dan "Salawaku" (perisai)', 'Senjata tradisional adalah warisan leluhur. Remaja teladan bisa mempelajari sejarahnya untuk mengenal akar budayanya'),\n(138, 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Translate: "We must preserve our culture and nature"', '"Kita harus melestarikan budaya dan alam kita"', 'Remaja teladan adalah generasi penerus yang bertanggung jawab menjaga warisan budaya dan alam'),\n(139, 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'Apa yang dimaksud dengan "Kolintang"?', 'Alat musik pukul dari kayu khas Minahasa yang telah menjadi warisan budaya tak benda UNESCO sejak 2019', 'Ini adalah kebanggaan daerah. Remaja teladan harus bangga dan mempromosikan Kolintang ke dunia'),\n(140, 'PARIWISATA, KEBUDAYAAN & BAHASA INGGRIS', 'How would you promote North Sulawesi tourism in English to foreign tourists?', '"Welcome to North Sulawesi! We have Bunaken, the world-class diving spot, breathtaking mountains like Mahawu and Lokon, and delicious traditional food like Tinutuan. Our people are friendly and our culture is rich. Come and enjoy the beauty of God''''s creation here!"', 'Remaja teladan harus mampu menjadi duta pariwisata yang handal, mempromosikan keindahan alam Sulut dalam Bahasa Inggris yang baik');\n